-- 20260414000005_storage_buckets.sql
-- ============================================================

-- Create storage buckets (idempotent)
insert into storage.buckets (id, name, public)
values
  ('avatars',        'avatars',        true),
  ('artwork-photos', 'artwork-photos', true)
on conflict (id) do nothing;

-- Storage RLS: anyone can read public buckets
create policy "avatars: public read"
  on storage.objects for select
  using (bucket_id = 'avatars');

create policy "avatars: owner upload"
  on storage.objects for insert
  with check (
    bucket_id = 'avatars'
    and auth.uid()::text = (storage.foldername(name))[1]
  );

create policy "avatars: owner delete"
  on storage.objects for delete
  using (
    bucket_id = 'avatars'
    and auth.uid()::text = (storage.foldername(name))[1]
  );

create policy "artwork-photos: public read"
  on storage.objects for select
  using (bucket_id = 'artwork-photos');

create policy "artwork-photos: owner upload"
  on storage.objects for insert
  with check (
    bucket_id = 'artwork-photos'
    and auth.uid()::text = (storage.foldername(name))[1]
  );

create policy "artwork-photos: owner delete"
  on storage.objects for delete
  using (
    bucket_id = 'artwork-photos'
    and auth.uid()::text = (storage.foldername(name))[1]
  );

-- ============================================================
-- 20260416000000_add_username.sql
-- ============================================================

-- =============================================================================
-- Add username column to users
-- Unique, indexed, required. Generated server-side during auth callback.
-- =============================================================================

alter table users
  add column username citext;

-- Backfill existing rows with a placeholder derived from id to satisfy NOT NULL
-- (safe because the column is newly added and no production users exist yet).
update users
  set username = 'user-' || substring(id::text from 1 for 8)
  where username is null;

alter table users
  alter column username set not null;

create unique index users_username_key on users (username);

-- ============================================================
-- 20260417000000_add_terms_accepted_at.sql
-- ============================================================

-- =============================================================================
-- Add terms_accepted_at column to users
-- Timestamp set when the user ticks the Terms + Privacy agreement on Step 1.
-- Nullable; existing rows keep null. Set once, never overwritten.
-- =============================================================================

alter table users
  add column terms_accepted_at timestamptz;

-- ============================================================
-- 20260420000000_add_is_test_user.sql
-- ============================================================

-- =============================================================================
-- Add is_test_user flag to users
-- Used by read queries (landing stats, discover, following, admin, etc.) to
-- filter out development test accounts seeded by the /dev/test-login utility.
-- Defaults to false; indexed for fast filtering on aggregate counts.
-- =============================================================================

alter table users
  add column is_test_user boolean not null default false;

-- Backfill: any rows whose email sits in the dev test domain get flagged.
update users
  set is_test_user = true
  where email ilike '%@test.ftae.local';

create index users_is_test_user_idx on users (is_test_user);

-- ============================================================
-- 20260421000000_add_photo_focal_point.sql
-- ============================================================

-- =============================================================================
-- Add focal point to artwork_photos
-- Fractions [0, 1] of the photo's natural dimensions marking where the subject
-- sits. Square thumbnail surfaces (Profile grid, Discover grid) render with
-- CSS `object-position: X% Y%` derived from these so the subject stays in
-- view instead of the geometric center being cropped.
-- =============================================================================

alter table artwork_photos
  add column focal_x real not null default 0.5,
  add column focal_y real not null default 0.5;

alter table artwork_photos
  add constraint artwork_photos_focal_x_range check (focal_x >= 0 and focal_x <= 1),
  add constraint artwork_photos_focal_y_range check (focal_y >= 0 and focal_y <= 1);

-- ============================================================
-- 20260421000001_drop_photo_type.sql
-- ============================================================

-- =============================================================================
-- Drop photo_type from artwork_photos
-- The column was scaffolded with enum values front/back/detail/shipping, but
-- assignments were position-based and the UI never surfaced the distinction.
-- Thumbnail selection now relies solely on sort_order (first photo wins).
-- =============================================================================

alter table artwork_photos drop column photo_type;

drop type artwork_photo_type;

-- ============================================================
-- 20260422000000_purge_stale_signups.sql
-- ============================================================

-- =============================================================================
-- Purge stale signups
--
-- A user who clicks the magic link triggers a row in `auth.users` plus a
-- public.users row. If they never accept the Terms + Privacy on Step 1
-- (terms_accepted_at remains null), we should not retain their email
-- indefinitely. After a 3-day grace window, the row is purged from both
-- public.users (cascading to dependent rows) and auth.users.
--
-- Implementation:
--   - SECURITY DEFINER function owned by `postgres` so it can touch auth.users.
--   - Scheduled daily via pg_cron.
--   - Idempotent — safe to run repeatedly.
--   - Users who accepted ToS at any point are never purged, regardless of
--     subsequent activity.
-- =============================================================================

create extension if not exists pg_cron with schema extensions;

create or replace function public.purge_stale_signups()
returns integer
language plpgsql
security definer
set search_path = public, extensions, auth
as $$
declare
  purged_count integer;
begin
  with purgees as (
    delete from public.users
    where terms_accepted_at is null
      and created_at < now() - interval '3 days'
    returning id
  ),
  auth_purge as (
    delete from auth.users
    where id in (select id from purgees)
    returning id
  )
  select count(*) into purged_count from auth_purge;

  return coalesce(purged_count, 0);
end;
$$;

revoke all on function public.purge_stale_signups() from public;

select cron.schedule(
  'purge-stale-signups-daily',
  '17 4 * * *',
  $$ select public.purge_stale_signups(); $$
);

-- ============================================================
-- 20260423000000_add_username_changed_at.sql
-- ============================================================

-- =============================================================================
-- Track the timestamp of the last successful username change.
-- NULL = the user has never explicitly changed their username via the
-- management flow. The first onboarding pick does NOT set this column, so
-- the user can still go to Edit Username after completing onboarding without
-- hitting the 30-day cooldown. Every successful change-via-magic-link sets
-- this to now(); the cooldown is enforced at >= 30 days from this timestamp.
-- =============================================================================

alter table users
  add column username_changed_at timestamptz;

-- ============================================================
-- 20260423000001_rls_explicit_denies.sql
-- ============================================================

-- =============================================================================
-- Defense-in-depth: explicit RLS deny policies on append-only tables.
--
-- Postgres RLS denies any operation that has no matching policy, so the
-- previous behavior was already locked down at runtime. The risk these
-- explicit denies guard against is a future migration that adds a permissive
-- `for all` or `for update` policy without realizing the table is meant to be
-- append-only — an explicit `using (false)` makes that intent visible and
-- forces anyone changing it to do so deliberately.
-- =============================================================================

-- ---------------------------------------------------------------------------
-- MEMBERSHIP_CREDITS — append-only ledger.
-- ---------------------------------------------------------------------------

create policy "membership_credits: no update"
  on membership_credits for update
  using (false);

create policy "membership_credits: no delete"
  on membership_credits for delete
  using (false);

-- ---------------------------------------------------------------------------
-- TRADE_PROPOSALS — proposals are immutable once created.
-- ---------------------------------------------------------------------------

create policy "trade_proposals: no update"
  on trade_proposals for update
  using (false);

create policy "trade_proposals: no delete"
  on trade_proposals for delete
  using (false);

-- ---------------------------------------------------------------------------
-- ADMIN_ACTIONS — audit log is append-only.
-- ---------------------------------------------------------------------------

create policy "admin_actions: no update"
  on admin_actions for update
  using (false);

create policy "admin_actions: no delete"
  on admin_actions for delete
  using (false);

-- ---------------------------------------------------------------------------
-- MEDIUMS — canonical list managed via migrations only.
--
-- The original "mediums: admin write" policy used `for all`, which let
-- admins UPDATE/DELETE canonical rows from the app. Renaming or deleting a
-- medium would corrupt the discovery filter and break user_mediums FK
-- references. Replace with INSERT-only so admins can add new mediums but
-- not mutate the existing ones; renames/removals must go through a
-- migration with the FK churn handled deliberately.
-- ---------------------------------------------------------------------------

drop policy if exists "mediums: admin write" on mediums;

create policy "mediums: admin insert"
  on mediums for insert
  with check (current_user_role() in ('admin', 'super_admin'));

create policy "mediums: no update"
  on mediums for update
  using (false);

create policy "mediums: no delete"
  on mediums for delete
  using (false);
